    "# Convert SleepDay class from chr to POSIXct\n",
    "clean_daySleep$SleepDay = as.POSIXct(clean_daySleep$SleepDay, format=\"%m/%d/%Y %I:%M:%S %p\")\n",
    "\n",
    "# Format the SleepDay column to date format under the new column named 'Date'\n",
    "clean_daySleep$Date <- format(clean_daySleep$SleepDay, format = \"%m/%d/%Y\")\n",
    "\n",
    "# Move Date column after Id column \n",
    "cleanv2_daySleep <- clean_daySleep %>% relocate(Date, .after='Id')\n",
    "\n",
    "# Delete SleepDay column\n",
    "cleanv2_daySleep$SleepDay <- NULL"
   ]
