    "         VeryActiveDistance) %>% \n",
    "    summary()\n",
    "\n",
    "hourlyIntensities %>%\n",
    "    select(TotalIntensity, AverageIntensity) %>%\n",
    "    summary()\n",
    "\n",
    "cleanv2_daySleep %>%\n",
    "    select(TotalSleepRecords, TotalMinutesAsleep, TotalTimeInBed) %>%\n",
    "    summary()"
   ]
