   "source": [
    "avg_Activity_Sleep <- daily_Activity_Sleep %>% group_by(Id) %>% \n",
    "    summarize(avg_TotalSteps = mean(TotalSteps), \n",
    "    avg_TotalDistance = mean(TotalDistance), \n",
    "    avg_Calories = mean(Calories), \n",
    "    avg_VeryActiveDistance = mean(VeryActiveDistance),\n",
    "    avg_VeryActiveMinutes = mean(VeryActiveMinutes),\n",
    "    avg_SedentaryMinutes = mean(SedentaryMinutes),\n",
    "    avg_TotalMinutesInBed = mean(TotalTimeInBed), \n",
    "    avg_TotalMinutesAsleep = mean(TotalMinutesAsleep))\n",
    "\n",
    "head(avg_Activity_Sleep)"
   ]
