   "source": [
    "# create dataset omitting data with '0' VeryActiveMinutes\n",
    "\n",
    "VeryActive_data <- subset(daily_Activity_Sleep, VeryActiveMinutes != 0)\n",
    "\n",
    "ggplot(data = VeryActive_data, mapping = aes (x = VeryActiveMinutes, y = Calories)) + geom_point() + geom_smooth() +\n",
    "    labs(x = \"Very Active Minutes\", y = \"Calories Burned\", title = \"Very Active Minutes vs. Calories Burned\")"
   ]
  },
