   "source": [
    "hourly_total_Int <- hourlyIntensities %>% \n",
    "  group_by(Time) %>%\n",
    "  drop_na() %>%\n",
    "  summarise(mean_total_Int = mean(TotalIntensity))\n",
    "\n",
    "ggplot(data = hourly_total_Int, aes(x = Time, y = mean_total_Int)) + geom_histogram(stat = \"identity\", fill = 'darkblue') +\n",
    "    theme(axis.text.x = element_text(angle = 90)) + labs(x = \"Time\", y = \"Mean Total Intensities\", title = \"Average Total Intensity vs. Time\")"
   ]
  },
